var e=`/assets/%E8%83%BD%E5%8A%9B%E7%94%BB%E5%83%8F-PYBSBPxW.png`,t=`/assets/%E6%8E%A8%E8%8D%90%E7%AE%97%E6%B3%95%E9%A2%98%E5%8D%95-Bs-xQ9nX.png`,n=`/assets/%E7%9F%A5%E8%AF%86%E6%A0%91-GHn_05Cr.png`,r=`/assets/%E4%B8%BB%E7%95%8C%E9%9D%A2-CYBECVW5.png`,i=`/assets/%E8%90%8C%E5%AE%A0%E5%BD%A2%E8%B1%A1-CsoDvy5B.png`,a={dynamic:{name:`动态难度调节子系统`,goal:`通过维持挑战难度与能力水平的平衡，提高学习者心流状态触发的概率`,icon:`01`},immersive:{name:`沉浸感优化子系统`,goal:`通过营造无干扰的专注环境，延长学习者在心流状态的停留时间`,icon:`02`}},o=[{id:1,subsystem:`dynamic`,moduleNo:`1.1`,title:`能力评估模型`,description:`基于知识图谱构建学习者能力画像，动态分析节点完成情况，为挑战评估与动态匹配提供精准输入。`,tags:[`能力画像`,`知识图谱`,`可视化分析`],link:`https://github.com/dim273/t-pet/blob/master/media/TreeNode/data.js`,year:`2024`,role:`核心开发`,status:`已完成`,detailedDescription:`基于知识图谱的构建与设计，本系统将学习者的节点完成情况进行可视化分析，并将其作为学习者的能力画像，为后续的挑战评估模型、动态匹配算法以及问题分解算法提供学习者的能力数据。知识树采用多层级树形结构，每个节点包含 id、状态图标（🔒未解锁 / 🚩进行中 / ⭐已完成）、unlocked 解锁状态、questionList 关联题单、parent 父节点（支持多父节点）等字段。能力画像通过 passedSet 记录已通过题目，completionCache 缓存节点完成度，形成对学习者当前能力的动态评估。解锁机制采用自底向上迭代式状态传播：节点是否「已完成」取决于关联题单是否全部通过，节点是否「已解锁」取决于所有父节点是否都已完成，循环最多 5 轮直至状态稳定。性能上采用单调性优化（已完成节点不再重算）、completionCache 缓存与 passedSet 的 O(1) 查找，并用签名比对判断已通过题目列表是否变化。`,highlights:[`基于知识图谱多层级树形结构动态构建学习者能力画像`,`passedSet 记录已通过题目 + completionCache 缓存节点完成度`,`自底向上迭代式状态传播，为三大算法提供精准能力数据输入`],techStack:[`知识图谱`,`状态传播`,`Set/Map`,`可视化分析`],imageUrl:e},{id:2,subsystem:`dynamic`,moduleNo:`1.2`,title:`挑战评估模型`,description:`基于最近发展区理论，从四个维度量化题目与学习者能力的适配性，防止认知超载与厌倦感。`,tags:[`ZPD理论`,`适配性量化`,`评测引擎`],link:`https://github.com/dim273/t-pet/blob/master/media/ProblemPage/app.js`,year:`2024`,role:`核心开发`,status:`已完成`,detailedDescription:`为计算题目难度与学习者最近发展区的适配性，本系统从以下四个方面进行适配性的量化：标签掌握度分数、知识树状态分数、难度匹配分数以及标签数量奖励分数。对于标签掌握度分数，算法对掌握程度为 60% 左右的知识点评价较高（2 - |mastery - 0.6| * 4），既不会让学习者认为过于简单，也不会过于困难，符合学习者的最近发展区。对于知识树状态分数，算法对处于当前学习路径中的节点（+5 分）或已解锁但未完成的节点（+2 分）评价较高。对于难度匹配分数，采用自适应处理，对于已经完成的节点，算法会对难度较大的题目评价较高；而当节点完成度较低时，则对中等或是简单题目评价较高。以上所有评价方式均符合维果茨基的最近发展区理论。适配性计算依赖本地评测引擎判定题目通过状态：从测试目录读取 .in/.out 数据，根据扩展名分发执行（.py→python、.js→node、.c→gcc、.cpp→g++），用 child_process.spawn 执行并捕获 stdout，逐用例对比返回 AC（通过）/ WA（答案错误）/ RE（运行错误）/ Timeout（超时）。`,highlights:[`四维适配性量化：标签掌握度 + 知识树状态 + 难度匹配 + 标签数量奖励`,`标签掌握度偏好 60% 附近，符合维果茨基最近发展区理论`,`本地多语言评测引擎（Python/JS/C/C++）判定题目通过状态`],techStack:[`ZPD理论`,`评分模型`,`child_process`,`gcc/g++`]},{id:3,subsystem:`dynamic`,moduleNo:`1.3`,title:`动态匹配算法`,description:`结合能力评估与挑战评估模型，主动筛选落在最近发展区的题目，将心流从偶然变为必然。`,tags:[`推荐算法`,`Top-5推荐`,`主动塑造`],link:`https://github.com/dim273/t-pet/blob/master/media/RecommendProblemList/recommendation.js`,year:`2024`,role:`算法设计`,status:`已完成`,detailedDescription:`该算法结合能力评估模型与挑战评估模型，对所有未通过题目计算与最近发展区的适配性，并选取分数最高的 5 道题目作为推荐题目以供学习者练习提升。通过将前述两个模型结合，系统实现了从「被动适应」到「主动塑造」的心流体验跨越——主动为学习者筛选并推荐恰好落在其最近发展区的题目。这些题目既不会因为过于简单而引发无聊感、导致注意力分散，也不会因为过于困难而触发认知超载与挫败感。通过这种主动塑造的方式，将心流状态从偶然事件转变为系统设计的必然结果，从而极大提高学习者触发心流状态的概率。最终按总分降序取前 5 道题推荐。`,highlights:[`结合能力评估与挑战评估，计算全量题目适配性`,`从「被动适应」到「主动塑造」，心流从偶然变必然`,`总分降序取 Top-5 推荐题目`],techStack:[`评分模型`,`推荐算法`,`ZPD理论`],imageUrl:t},{id:4,subsystem:`dynamic`,moduleNo:`1.4`,title:`问题分解算法`,description:`将大模型从「答案生成者」转为「学习辅助者」，依据能力画像动态调整任务细粒度，实现渐进式问题解决。`,tags:[`AI引导`,`DeepSeek`,`渐进式分解`],link:`https://github.com/dim273/t-pet/blob/master/out/AIAssistant/logic.js`,year:`2024`,role:`核心开发`,status:`已完成`,detailedDescription:`为了将大语言模型从「答案生成者」转向「辅助学习者」，本系统创新性地引入了问题分解算法。依据学习者能力画像动态调整任务细粒度，将复杂的编程问题分解为更简单的子问题，实现渐进式问题解决路径，降低其认知负荷。AI 助教模块基于 DeepSeek API 实现上下文感知的个性化辅导，支持三种提问模式：代码分析（注入当前编辑器活动文件代码）、题目引导（注入题目 .md 原文，截断 500 字）、知识讲解（注入知识点名称）。AI 基于学习进度摘要（getLearningProgressSummary）动态构造系统提示词，计算并注入已掌握知识、正在学习、未开始学习与最近发展区 ZPD 节点，要求 AI 优先用已掌握知识做类比切入、禁止直接给出完整代码、引导用户逐步攻克正在学习的内容。后端通过 Node.js https 模块调用 DeepSeek API，启用 stream: true 逐块解析 SSE 数据，前端用 requestAnimationFrame 节流渲染（约 60fps），历史消息采用滑动窗口只取最近 6 条控制 token 消耗。大模型不再直接为学习者提供题目代码，而是根据能力水平帮助分解与引导，让学习者逐步自主编写完整代码。`,highlights:[`大模型从「答案提供者」转换为「学习辅助者」`,`依据能力画像动态调整任务细粒度，实现渐进式分解`,`三种提问模式 + ZPD 系统 Prompt + 禁止直接给代码的防越狱规则`],techStack:[`DeepSeek API`,`SSE流式渲染`,`ZPD理论`,`requestAnimationFrame`]},{id:5,subsystem:`immersive`,moduleNo:`2.1`,title:`目标可视化与进度管理`,description:`基于 NOI 大纲构建知识图谱，游戏化闯关设计将长期目标拆分为短期成就，持续激发探索动力。`,tags:[`知识图谱`,`闯关设计`,`可视化`],link:`https://github.com/dim273/t-pet/blob/master/media/TreeNode/logic.js`,year:`2024`,role:`核心开发`,status:`已完成`,detailedDescription:`本项目严格遵循 2025 年最新发布的 NOI 大纲整理出所有编程知识节点，并根据知识节点的先修后继关系绘制出知识图谱。由于编程体系内的知识节点繁多，本项目将知识图谱中的所有节点系统性地组织为「一级知识模块」和「二级核心技能」两级结构。其中，每一个一级节点代表一个宏观的知识点（例如，动态规划、图论等），而其内部再次细分为多个具体的二级节点（例如：背包问题、最短路径算法等）。本系统采用游戏化闯关式设计，每一位学习者都必须通过二级节点所包含的所有题目以攻克每一个二级节点，只有当隶属于同一个一级节点的所有二级节点均被成功解锁后，该一级节点的后继节点才能被解锁。知识树解锁机制采用自底向上迭代式状态传播：节点是否「已完成」取决于关联题单是否全部通过，节点是否「已解锁」取决于所有父节点是否都已完成，循环最多 5 轮直至状态稳定。连接线通过 getBoundingClientRect 获取父子节点坐标，用三角函数计算角度和长度动态绘制。`,highlights:[`基于 2025 NOI 大纲，两级结构（一级知识模块 + 二级核心技能）`,`游戏化闯关式设计，先修后继关系确保认知与难度匹配`,`自底向上迭代式状态传播，getBoundingClientRect 动态绘制连接线`],techStack:[`NOI大纲`,`知识图谱`,`状态机`,`DOM可视化`],imageUrl:n},{id:6,subsystem:`immersive`,moduleNo:`2.2`,title:`多模态交互系统`,description:`通过里程碑提示与进度条动画反馈，将长期学习目标量化为短期成就，持续激发学习动力与自我效能感。`,tags:[`里程碑反馈`,`进度可视化`,`成就系统`],link:`https://github.com/dim273/t-pet/blob/master/media/calender.html`,year:`2024`,role:`核心开发`,status:`已完成`,detailedDescription:`该模块通过知识树的可视化展示与闯关式设计，实现了将长期学习目标量化为短期成就的过程，可以持续激发学习者的探索动力。系统通过里程碑提示与进度条动画反馈等形式，将抽象的学习进度转化为直观的可视化指标。当学习者完成节点攻克、题目通过等行为时，系统即时给予多模态反馈：进度条动态更新、节点状态图标切换（🔒未解锁 → 🚩进行中 → ⭐已完成）、连接线高亮绘制。同时，评测 AC 后自动完成打卡（写入 checkInDays）并触发萌宠庆祝动作，形成「学习—反馈—激励」的正向循环，延长学习者在心流状态的停留时间。`,highlights:[`里程碑提示 + 进度条动画，长期目标量化为短期成就`,`节点状态图标切换（🔒未解锁 → 🚩进行中 → ⭐已完成）`,`评测 AC 自动打卡 + 萌宠庆祝，形成正向激励循环`],techStack:[`DOM API`,`动画反馈`,`成就系统`,`可视化`]},{id:7,subsystem:`immersive`,moduleNo:`2.3`,title:`聚焦模式设计`,description:`单 Webview 多页面 SPA 架构，简化与整合界面，减少多任务切换引发的注意力碎片化问题。`,tags:[`SPA架构`,`界面整合`,`状态机`],link:`https://github.com/dim273/t-pet/blob/master/out/extension.js`,year:`2024`,role:`架构设计`,status:`已完成`,detailedDescription:`本系统在界面设计上强调「简化」与「整合」，旨在减少复杂、混乱的界面所带来的注意力碎片化问题。项目复用同一个 Webview 实例，通过内部状态机切换页面内容，而非为每个功能注册独立的 WebviewView。用 _page 字段维护当前页面状态（login、main、tree、list、problem、aiChat、abilityMap 等 10+ 页面），每次切换页面时调用 updateWebviewContent() 根据状态返回对应 HTML 字符串重新赋值给 webview.html，实现整页重渲染。同时维护 _history 栈实现返回上一页功能。将必要的功能进行整合，可以快速实现界面的切换与跳转，减少学习者因界面切换而浪费的时间，为编程新手提供无干扰的沉浸式代码实践环境，维持学习者的心流状态。资源注入方面，HTML 中的 CSS/JS 路径通过 webview.asWebviewUri() 转换为 vscode-webview:// 协议的可信 URI，并设置 32 位随机 nonce 防止 XSS。`,highlights:[`单 Webview 承载 10+ 页面，状态机路由切换`,`简化与整合界面，减少注意力碎片化`,`_history 历史栈 + CSP nonce 安全策略 + asWebviewUri 可信注入`],techStack:[`VS Code Extension API`,`状态机`,`postMessage`,`Webview`],imageUrl:r},{id:8,subsystem:`immersive`,moduleNo:`2.4`,title:`认知-情感协同萌伴`,description:`通过 Hack VS Code 内核注入 Live2D 萌伴，基于行为交互给予实时反馈，解决认知训练与情感激励割裂痛点。`,tags:[`内核Hack`,`Live2D`,`情感协同`],link:`https://github.com/dim273/t-pet/blob/master/out/live2dModify/Main.js`,year:`2024`,role:`核心技术`,status:`已完成`,detailedDescription:`本模块的核心原理是通过 Hack VS Code 的 workbench.js 注入自定义 JS 代码，在主窗口创建一个加载了 PixiJS + Live2D Cubism Core 的 iframe，以 WebGL 方式渲染带触摸交互的 Live2D 模型。VS Code 本质是 Electron 应用，主界面由 workbench.js 驱动，项目定位目标文件 out/vs/code/electron-browser/workbench/workbench.js 后，将 res/live2d/ 目录（含模型、渲染引擎、配置）拷贝到 workbench 同级目录，用注释标记包裹（/*ext-xxx-start*/ ... /*ext-xxx-end*/）追加 Live2d 类代码到 workbench.js 末尾，卸载时用正则匹配注释区间移除注入代码。萌伴可以在你编码的时候给予鼓励，在提交测试之后，如果错误会说出鼓励的话语，正确则会夸奖；同时还会根据你进入的时间打招呼。该系统基于学习者行为交互的实时识别，构建萌伴的动态行为决策树，通过给予不同反馈效果实现学习动机维持，解决传统教育工具中认知训练与情感激励割裂的痛点，以维持学习者的心流状态。`,highlights:[`Hack workbench.js 注入 Live2d 类，突破 Webview 沙箱限制`,`PixiJS + Live2D Cubism Core + WebGL 渲染 + 触摸交互`,`行为决策树驱动实时反馈：编码鼓励 / 错误安慰 / 正确夸奖 / 时间问候`],techStack:[`Electron`,`Pixi.js`,`Live2D Cubism SDK`,`workbench.js`,`WebGL`],imageUrl:i}];export{a as n,r,o as t};